begin; create extension if not exists pgtap with schema extensions; select plan(12);
select has_table('public','assets','assets exist'); select has_table('public','asset_uploads','reservations exist'); select has_table('public','asset_credits','credits exist'); select has_table('public','user_storage_usage','user quota exists'); select has_table('public','global_storage_usage','global quota exists');
select ok((select bool_and(relrowsecurity) from pg_class where oid=any(array['public.assets'::regclass,'public.asset_uploads'::regclass,'public.asset_credits'::regclass,'public.user_storage_usage'::regclass,'public.global_storage_usage'::regclass])),'all asset tables use RLS');
select is((select count(*) from storage.buckets where id in ('source-audio','workspace-snapshots','derived-assets') and not public),3::bigint,'three private buckets'); select is((select file_size_limit from storage.buckets where id='source-audio'),47185920::bigint,'source bucket limit');
select has_function('public','reserve_source_asset',array['uuid','bigint','text','text','integer','text'],'reserve command exists'); select has_function('public','complete_source_upload',array['uuid'],'completion command exists');
select is((select count(*) from information_schema.role_table_grants where grantee in ('anon','authenticated') and table_schema='public' and table_name in ('assets','asset_uploads','asset_credits','user_storage_usage','global_storage_usage') and privilege_type<>'SELECT'),0::bigint,'no direct application writes');
select is((select count(*) from pg_proc p join pg_namespace n on n.oid=p.pronamespace cross join lateral aclexplode(coalesce(p.proacl,acldefault('f',p.proowner))) a where n.nspname='private' and a.grantee=0 and a.privilege_type='EXECUTE'),0::bigint,'private functions have no PUBLIC execute'); select * from finish(); rollback;
